mapper.select:
        SELECT
            p.place_id,
            p.title,
            p.addr1,
            p.first_image1,
            p.category_code1,
            p.category_code2,
            COUNT(pl.user_id) AS like_count
        FROM places p
        LEFT JOIN place_likes pl ON p.place_id = pl.place_id


		        AND p.area_code = #{areaCode}


		        AND p.district_code = #{districtCode}


		        AND p.category_code1 = #{category1}


		        AND p.category_code2 = #{category2}


		        AND p.title LIKE CONCAT('%', #{keyword}, '%')

		    AND p.addr1 IS NOT NULL AND p.addr1 != ''

        GROUP BY p.place_id
        ORDER BY like_count DESC
        LIMIT #{limitSize}
        OFFSET #{offset}
